node -e "
const { execSync } = require('child_process');

try {
  const branch = execSync('git rev-parse --abbrev-ref HEAD', { encoding: 'utf8' }).trim();

  if (branch === 'main' || branch === 'HEAD') {
    process.exit(0);
  }

  const branchCreatedOutput = execSync(
    'git log --reverse --format=%ci ' + branch + ' --not main',
    { encoding: 'utf8' }
  ).trim();

  if (!branchCreatedOutput) {
    process.exit(0);
  }

  const firstCommitDate = new Date(branchCreatedOutput.split('\n')[0]);
  const now = new Date();

  const msPerDay = 1000 * 60 * 60 * 24;
  const daysDiff = (now - firstCommitDate) / msPerDay;

  // Approximate working days (weekdays only)
  let workingDays = 0;
  const cursor = new Date(firstCommitDate);
  while (cursor <= now) {
    const day = cursor.getDay();
    if (day !== 0 && day !== 6) workingDays++;
    cursor.setDate(cursor.getDate() + 1);
  }

  if (workingDays > 2) {
    console.warn('TBD POLICY WARNING: Branch \"' + branch + '\" is ' + workingDays + ' working days old.');
    console.warn('Engineering policy §1.2 requires branches to be merged within 2 working days.');
    console.warn('Action: Either merge now, split the task, or put incomplete work behind a feature flag.');
    // Warning only — do not block (exit 0)
  }
} catch (e) {
  // If git commands fail (not a git repo, etc.), do not block
}

process.exit(0);
"
